enable_timer() {
  systemctl daemon-reload 2>/dev/null || true

  # Generate timer drop-in from configured schedule
  local dropin_dir="/etc/systemd/system/updatebtw-update.timer.d"
  mkdir -p "$dropin_dir"
  local calendar
  calendar="$(calendar_from_config)"
  printf '[Timer]\nOnCalendar=%s\n' "$calendar" > "$dropin_dir/schedule.conf"
  chmod 644 "$dropin_dir/schedule.conf"

  systemctl daemon-reload 2>/dev/null || true
  systemctl enable --now updatebtw-update.timer 2>/dev/null || true
  if [ "$RUN_AT_BOOT" = "true" ]; then
    systemctl enable updatebtw-boot.service 2>/dev/null || true
  fi
}

